function formatDate(dateStr){if(!dateStr)return"";const[year,month,day]=dateStr.split("-").map(Number);const date=new Date(year,month-1,day);return date.toLocaleDateString("en-US",{year:"numeric",month:"short",day:"numeric"})}function createCard(item){const card=document.createElement("div");card.className="card";const watchedHTML=item.watched?`<p class="card-date">Finished Watching:<br>${formatDate(item.watched)}</p>`:"";card.innerHTML=`
        <div class="poster-container">
            <img src="${item.poster}" alt="${item.title} Poster">
        </div>
        <div class="card-content">
            <h3 class="card-title">${item.title}</h3>
            <p class="card-rating">${item.rating}</p>
            ${watchedHTML}
        </div>
    `;card.onclick=()=>openModal(item.title,item.review);return card}function extractRatingScore(ratingStr){const match=ratingStr.match(/\((\d+(\.\d+)?)\/10\)/);return match?parseFloat(match[1]):0}function sortCategoryData(data){return data.sort((a,b)=>{const scoreA=extractRatingScore(a.rating);const scoreB=extractRatingScore(b.rating);if(scoreA!==scoreB)return scoreB-scoreA;const weightA=a.weight??9999;const weightB=b.weight??9999;if(weightA!==weightB)return weightA-weightB;const dateA=a.watched?new Date(a.watched):new Date(0);const dateB=b.watched?new Date(b.watched):new Date(0);return dateB-dateA})}function populateCards(){if(!window.categoryData)return;const count=document.getElementById("entry-count");if(count){count.querySelector("strong").textContent=window.categoryData.length}const sortedData=sortCategoryData(window.categoryData);sortedData.forEach(item=>{const tierGrid=document.getElementById(`${item.tier}-tier`);if(tierGrid)tierGrid.appendChild(createCard(item))})}const modal=document.getElementById("reviewModal");const modalTitle=document.getElementById("modalTitle");const modalReview=document.getElementById("modalReview");const closeBtn=document.querySelector(".close");function openModal(title,review){modalTitle.textContent=title+" Review";modalReview.innerHTML=review.replace(/\n/g,"<br>");modal.style.display="block"}closeBtn.onclick=()=>modal.style.display="none";window.onclick=event=>{if(event.target===modal)modal.style.display="none"};